    ('cat_board_books', 1, 1, 'visible', true, false, 'Best for bold face pages', 'Baby Touch: Faces: a black-and white-book', 'Ladybird', 'Bookshop.org UK', 'https://uk.bookshop.org/p/books/baby-touch-faces-a-black-and-white-book-ladybird/cfee1c58ca5fa534?ean=9780241391723', NULL, 'GBP 6.64', 'in_stock', NULL, 'A sturdy Ladybird board book of large black and white faces, sized for newborn focus and early shared looking on the sofa or changing mat.', 'Vision is still learning distance in the first months, so big simple faces beat busy colour spreads. A board book you can hold close turns a feed break into a short look and chat. Leave it for awake cuddles, not the cot.', 'Vision is still learning distance in the first months, so big simple faces beat busy colour spreads. A board book you can hold close turns a feed break into a short look and chat. Leave it for awake cuddles, not the cot.', NULL, NULL, true, 'Good gift', NULL, NULL, NULL, ARRAY[]::text[], 'none'),
    ('cat_board_books', 2, 2, 'visible', true, true, 'Best for a small set', 'Usborne Baby’s Very First Black & White Books – 4 Board Book Set (Animals, Hello!, Outdoors, Bedtime)', 'Usborne', 'Books4People.co.uk', 'https://www.books4people.co.uk/products/usborne-babys-very-first-black-and-white-4-books-set?srsltid=AfmBOorONokiobWgKxFHSwlSpjeK3Jj6nzKGgCSHfLMBfNK-FUKM9yBB', NULL, 'GBP 9.89', 'in_stock', NULL, 'A Usborne set of four high-contrast board books covering animals, hellos, outdoors and bedtime scenes, all in bold black and white for early looking.', 'One book gets sticky milk on it fast. A small set means you can rotate themes without buying five singles at once. High-contrast still matches what young eyes notice first, and the sturdy boards survive the grab that comes next.', 'One book gets sticky milk on it fast. A small set means you can rotate themes without buying five singles at once. High-contrast still matches what young eyes notice first, and the sturdy boards survive the grab that comes next.', NULL, NULL, true, 'Good gift', NULL, NULL, NULL, ARRAY[]::text[], 'none'),
    ('cat_board_books', 3, 3, 'visible', true, true, 'Best for slider peekaboo', 'Peekaboo Bear', 'Nosy Crow', 'Amazon UK', 'https://www.amazon.co.uk/Peekaboo-Bear-Ingela-P-Arrhenius/dp/1788005767', NULL, 'GBP 2.76', 'in_stock', NULL, 'An interactive Nosy Crow board book with easy sliders, friendly faces and forest animals, ending on a surprise mirror page for shared peekaboo.', 'By two to three months, a little reveal game starts to click. Sliders you operate for them keep the play gentle while faces stay the draw. The mirror ending adds one more face without needing a separate toy on the sofa.', 'By two to three months, a little reveal game starts to click. Sliders you operate for them keep the play gentle while faces stay the draw. The mirror ending adds one more face without needing a separate toy on the sofa.', NULL, NULL, true, 'Good gift', NULL, NULL, NULL, ARRAY[]::text[], 'none'),
    ('cat_board_books', 4, 4, 'visible', true, true, 'Best for simple face focus', 'Hello Baby: Faces', 'Roger Priddy', 'Priddy Books (via Google Shopping fallback)', 'https://priddybooks.com/gb/books/hello-baby-faces/', NULL, 'GBP 4.99', 'unknown', NULL, 'A high-contrast Roger Priddy board book of clear faces and expressions, kept simple so very young babies can hold a look without visual clutter.', 'Busy pages lose them when focus is still short. Clear faces with strong contrast give you something to point at and name in a quiet voice. Useful when you want one book that does the face job cleanly, without gadgets or flaps in the way.', 'Busy pages lose them when focus is still short. Clear faces with strong contrast give you something to point at and name in a quiet voice. Useful when you want one book that does the face job cleanly, without gadgets or flaps in the way.', NULL, NULL, true, 'Good gift', NULL, NULL, NULL, ARRAY[]::text[], 'google_shopping_fallback'),
    ('cat_board_books', 5, 5, 'visible', true, true, 'Best for pattern cut outs', 'Amazing Baby: Black and White', 'Emma Dodd', 'BookTrust (via Google Shopping fallback)', 'https://www.booktrust.org.uk/book-recommendations/bookfinder/amazing-baby-black-and-white/', NULL, 'GBP 5.99', 'unknown', NULL, 'An interactive Emma Dodd board book with cut out pages of black and white patterns, dots and stripes, plus a simple rhyme for shared looking and listening.', 'Patterns help as much as faces while sight is sharpening. Cut out pages let little fingers poke through while you hold the book steady. The rhyme keeps your voice in the game without turning shared looking into homework on the sofa.', 'Patterns help as much as faces while sight is sharpening. Cut out pages let little fingers poke through while you hold the book steady. The rhyme keeps your voice in the game without turning shared looking into homework on the sofa.', NULL, NULL, true, 'Good gift', NULL, NULL, NULL, ARRAY[]::text[], 'google_shopping_fallback'),
    ('cat_burp_cloths_muslins', 1, 1, 'visible', true, false, 'Best for everyday milk spills', 'Essentials Cotton Muslin Squares - 5 Pack - Blushing Bunnies', 'aden + anais', 'Natural Baby Shower', 'https://www.naturalbabyshower.co.uk/products/aden-anais-essentials-5-pack-cotton-muslin-squares-blushing-bunnies', NULL, 'GBP 22.95', 'in_stock', NULL, 'A pack of five soft 100% cotton aden + anais muslin squares in Blushing Bunnies prints, for burping, wiping and quick shoulder cover during feeds.', 'Wind and milk dribble are the wallpaper of one to three months. A pack of five means one is always dry while another is in the wash. Soft cotton muslin works on the shoulder, the changing mat and the sofa without reading like a medical cloth.', 'Wind and milk dribble are the wallpaper of one to three months. A pack of five means one is always dry while another is in the wash. Soft cotton muslin works on the shoulder, the changing mat and the sofa without reading like a medical cloth.', NULL, NULL, false, 'Parent buy', NULL, NULL, NULL, ARRAY[]::text[], 'none'),
    ('cat_burp_cloths_muslins', 2, 2, 'visible', true, true, 'Best for thicker burp cloths', 'Cotton Muslin Burp Cloths (3 Pack)', 'MuslinZ', 'MuslinZ', 'https://muslinz.co.uk/products/cotton-muslin-burp-cloths', NULL, 'GBP 9.99', 'in_stock', NULL, 'A pack of three six layer MuslinZ cotton burp cloths, soft and highly absorbent, shaped for catching bigger spit ups on the shoulder.', 'Some babies do more than a polite dribble. Extra layers soak up a proper spit up before it hits your shirt. Keep a couple by the feeding chair and treat them as workhorses rather than pretty extras you are afraid to use.', 'Some babies do more than a polite dribble. Extra layers soak up a proper spit up before it hits your shirt. Keep a couple by the feeding chair and treat them as workhorses rather than pretty extras you are afraid to use.', NULL, NULL, false, 'Parent buy', NULL, NULL, NULL, ARRAY[]::text[], 'none'),
    ('cat_burp_cloths_muslins', 3, 3, 'visible', true, true, 'Best for high street value', '5 Pack Pure Cotton Muslin Squares', 'M&S', 'Marks & Spencer', 'https://www.marksandspencer.com/5pk-pure-cotton-muslin-squares/p/clp60616744', NULL, 'GBP 8.00', 'in_stock', NULL, 'A practical Marks and Spencer pack of five pure cotton muslin squares, soft enough for baby skin and ready for everyday spills and clean ups.', 'You do not need a boutique pack for every cloth in the house. An M&S pack of five tops up the stash when the pretty ones are all in the wash. Plain cotton still does the burp and wipe job well at this age.', 'You do not need a boutique pack for every cloth in the house. An M&S pack of five tops up the stash when the pretty ones are all in the wash. Plain cotton still does the burp and wipe job well at this age.', NULL, NULL, false, 'Parent buy', NULL, NULL, NULL, ARRAY[]::text[], 'none'),
    ('cat_burp_cloths_muslins', 4, 4, 'visible', true, true, 'Best for plain white packs', 'Muslin Squares, Pack of 6, White', 'John Lewis', 'John Lewis', 'https://www.johnlewis.com/john-lewis-muslin-squares-pack-of-6-white/p230650111', NULL, 'GBP 8.00', 'in_stock', NULL, 'A pack of six plain white John Lewis cotton muslin squares, gentle for baby skin and useful for feeds, spills and quick clean ups around the house.', 'White muslins bleach back when life gets messy. A pack of six covers the early weeks when laundry never quite catches up. Swap them under the chin, over the shoulder and across the sofa without worrying about a print fading.', 'White muslins bleach back when life gets messy. A pack of six covers the early weeks when laundry never quite catches up. Swap them under the chin, over the shoulder and across the sofa without worrying about a print fading.', NULL, NULL, false, 'Parent buy', NULL, NULL, NULL, ARRAY[]::text[], 'none'),
    ('cat_burp_cloths_muslins', 5, 5, 'visible', true, true, 'Best for soft bamboo packs', 'Bamboo Muslin Squares', 'Panda London', 'Panda London', 'https://pandalondon.com/products/bamboo-muslin-squares', NULL, 'GBP 24.00', 'in_stock', NULL, 'Dual layer bamboo muslin squares from Panda London, soft and absorbent for spills and feeds, often sold in a gift box and ready to wash before first use.', 'If cotton feels scratchy on sensitive skin, bamboo muslin is a kinder backup. Still a working cloth for spit up and dribbles, not a display piece. Handy as a gift when parents already own a mountain of printed cotton squares.', 'If cotton feels scratchy on sensitive skin, bamboo muslin is a kinder backup. Still a working cloth for spit up and dribbles, not a display piece. Handy as a gift when parents already own a mountain of printed cotton squares.', NULL, NULL, false, 'Parent buy', NULL, NULL, NULL, ARRAY[]::text[], 'none'),
    ('cat_firm_flat_mattress', 1, 1, 'visible', true, false, 'Best for firm waterproof side', 'CuddleCo Lullaby Hypo-Allergenic Firm Baby Cot Bed Mattress (140x70cm)', 'CuddleCo', 'Amazon UK', 'https://www.amazon.co.uk/CuddleCo-Lullaby-Hypo-Allergenic-Bamboo-Mattress/dp/B07TKJMD9Q', NULL, 'GBP 69.99', 'in_stock', NULL, 'A firm CuddleCo cot bed mattress with a hypoallergenic core and one waterproof side, sized 140 by 70 centimetres for safe flat sleep from birth.', 'Safe sleep at this age wants firm and flat, not plush. A waterproof face saves the core when night feeds go messy. You get a lower price without dropping the firmness you need through the early months of night waking.', 'Safe sleep at this age wants firm and flat, not plush. A waterproof face saves the core when night feeds go messy. You get a lower price without dropping the firmness you need through the early months of night waking.', NULL, NULL, false, 'Parent buy', NULL, 'A new mattress is preferred where possible. Avoid soft, uneven or poorly fitting surfaces.', NULL, ARRAY[]::text[], 'none'),
    ('cat_firm_flat_mattress', 2, 2, 'visible', true, true, 'Best for dual sided growth', 'SnuzSurface Duo Dual Sided Cot Bed Mattress SnuzKot', 'Snüz', 'Snüz Official Website', 'https://www.snuz.co.uk/products/snuzsurface-duo-dual-sided-cot-bed-mattress-snuzkot', NULL, 'GBP 155.00', 'in_stock', NULL, 'A SnuzSurface Duo cot bed mattress with a firm baby side and a softer toddler side, plus a waterproof surface and washable cover for everyday spills.', 'You buy a mattress once and live with it for years. Starting firm for the newborn side keeps sleep guidance simple now, with a flip later when they are bigger. The washable cover helps when night feeds miss the muslin again.', 'You buy a mattress once and live with it for years. Starting firm for the newborn side keeps sleep guidance simple now, with a flip later when they are bigger. The washable cover helps when night feeds miss the muslin again.', NULL, NULL, false, 'Parent buy', NULL, 'A new mattress is preferred where possible. Avoid soft, uneven or poorly fitting surfaces.', NULL, ARRAY[]::text[], 'none'),
    ('cat_firm_flat_mattress', 3, 3, 'visible', true, true, 'Best for allergy minded sleep', 'Mother & Baby Pure Gold Anti Allergy Coir Pocket Sprung Cot Bed Mattress', 'Mother&Baby', 'Boots', 'https://www.google.com/search?tbm=shop&q=Mother+%26+Baby+Pure+Gold+Anti+Allergy+Coir+Pocket+Sprung+Cot+Bed+Mattress+UK', NULL, 'GBP 129.99', 'in_stock', NULL, 'A Mother and Baby Pure Gold anti allergy coir pocket sprung cot bed mattress with a moveable waterproof membrane and washable cover for a dry sleep surface.', 'Households watching allergies often want a cleaner sleep surface without giving up firm support. Coir and pocket springs keep the bed flat for newborns, while the membrane catches night spills. Check the waterproof layer sits where you need it after each wash.', 'Households watching allergies often want a cleaner sleep surface without giving up firm support. Coir and pocket springs keep the bed flat for newborns, while the membrane catches night spills. Check the waterproof layer sits where you need it after each wash.', NULL, NULL, false, 'Parent buy', NULL, 'A new mattress is preferred where possible. Avoid soft, uneven or poorly fitting surfaces.', NULL, ARRAY[]::text[], 'google_shopping'),
    ('cat_firm_flat_mattress', 4, 4, 'visible', true, true, 'Best for moisture control', 'Obaby Moisture Management Dual Core Mattress -140x70cm', 'Obaby', 'Obaby Official Website', 'https://www.obaby.co.uk/products/moisture-management-dual-core-mattress', NULL, 'GBP 180.00', 'in_stock', NULL, 'An Obaby dual core cot bed mattress with a firm coir side for babies, pocket springs for later, and a Tencel top panel for moisture and humidity management.', 'Warm rooms and night feeds make a damp sleep surface more likely. A top panel that manages moisture helps the mattress stay fresher between washes. Keep the firm coir face up while they are small, then flip when toddler nights arrive.', 'Warm rooms and night feeds make a damp sleep surface more likely. A top panel that manages moisture helps the mattress stay fresher between washes. Keep the firm coir face up while they are small, then flip when toddler nights arrive.', NULL, NULL, false, 'Parent buy', NULL, 'A new mattress is preferred where possible. Avoid soft, uneven or poorly fitting surfaces.', NULL, ARRAY[]::text[], 'none'),
    ('cat_firm_flat_mattress', 5, 5, 'visible', true, true, 'Best for hybrid firm support', 'Simba Hybrid Cot Bed Mattress', 'Simba', 'Simba Sleep Official Website', 'https://simbasleep.com/products/cot-bed-mattress', NULL, 'GBP 249.00', 'in_stock', NULL, 'A Simba hybrid cot bed mattress with multiple layers, a firm side for babies and a softer side for toddlers, plus strong breathability and a washable cover.', 'If you want one pricier mattress that covers baby and toddler years, a hybrid build keeps early firmness honest. Breathable layers help when the room runs warm. Still place them flat on their back with a clear cot, no extras.', 'If you want one pricier mattress that covers baby and toddler years, a hybrid build keeps early firmness honest. Breathable layers help when the room runs warm. Still place them flat on their back with a clear cot, no extras.', NULL, NULL, false, 'Parent buy', NULL, 'A new mattress is preferred where possible. Avoid soft, uneven or poorly fitting surfaces.', NULL, ARRAY[]::text[], 'none'),
    ('cat_high_contrast_cards', 1, 1, 'visible', true, false, 'Best for a big card stack', 'Baby Sensory Cards - 60 Black and White High Contrast Baby Flash Cards', 'Little Seeds', 'Amazon UK', 'https://www.amazon.co.uk/Newborn-Essentials-Sensory-Contrast-Stimulation/dp/B0GWSNZ6R5', NULL, 'GBP 6.99', 'in_stock', NULL, 'A sixty card Little Seeds pack of black and white high-contrast flash cards for short supervised looking sessions on the mat or propped near the changing table.', 'Young eyes notice strong contrast before soft pastels. A big stack lets you rotate images so the same five cards do not go floppy with milk. Keep sessions tiny and face to face, and never leave loose cards in the sleep space.', 'Young eyes notice strong contrast before soft pastels. A big stack lets you rotate images so the same five cards do not go floppy with milk. Keep sessions tiny and face to face, and never leave loose cards in the sleep space.', NULL, NULL, true, 'Good gift', NULL, NULL, NULL, ARRAY[]::text[], 'none'),
    ('cat_high_contrast_cards', 2, 2, 'visible', true, true, 'Best for gallery style cards', 'Wee Gallery Baby Art Cards, Black and White, 0-12 Months', 'Wee Gallery', 'Amazon UK', 'https://www.amazon.co.uk/Wee-Gallery-Art-Cards-Baby/dp/B07SVC4NV3', NULL, 'GBP 34.59', 'in_stock', NULL, 'Wee Gallery black and white baby art cards for roughly birth to twelve months, with bold animal and shape designs meant for short shared looking on the floor.', 'Some card packs look clinical. Wee Gallery keeps the contrast strong while the drawings stay warmer in the living room. Use one or two at a time during tummy time or a cuddle, then put the pack away before clutter builds.', 'Some card packs look clinical. Wee Gallery keeps the contrast strong while the drawings stay warmer in the living room. Use one or two at a time during tummy time or a cuddle, then put the pack away before clutter builds.', NULL, NULL, true, 'Good gift', NULL, NULL, NULL, ARRAY[]::text[], 'none'),
    ('cat_high_contrast_cards', 3, 3, 'visible', true, true, 'Best for a thick card book', 'beiens Newborn Essentials Sensory Toys Cards, 160 Page Black White Visual Stimulation Learning Activity Cards', 'beiens', 'Amazon UK', 'https://www.amazon.co.uk/beiens-Contrast-Flashcard-Stimulation-Educational/dp/B07WZT8DTD', NULL, 'GBP 13.99', 'in_stock', NULL, 'A thick beiens black and white visual card set bound for easy flipping, aimed at short newborn looking practice rather than long teaching sessions.', 'Loose cards vanish under the sofa. A bound set stays in one place while you flip for a few seconds of focus. Stick to high-contrast pages now and leave the later colour stages in the pack for the months ahead.', 'Loose cards vanish under the sofa. A bound set stays in one place while you flip for a few seconds of focus. Stick to high-contrast pages now and leave the later colour stages in the pack for the months ahead.', NULL, NULL, true, 'Good gift', NULL, NULL, NULL, ARRAY[]::text[], 'none'),
    ('cat_high_contrast_cards', 4, 4, 'visible', true, true, 'Best for direct brand cards', 'Priya & Peanut 0+ Month Newborn Sensory Cards', 'Priya & Peanut', 'Priya & Peanut', 'https://www.priyaandpeanut.com/products/0-6-month-newborn-sensory-flashcard-collection', NULL, 'GBP 14.00', 'in_stock', NULL, 'Priya and Peanut newborn sensory cards from birth upwards, with high-contrast images for brief supervised looking on the playmat or during a quiet cuddle.', 'Buying direct can be simpler when Amazon listings look noisy. These cards still do the early contrast job without claiming to teach a syllabus. Pair a card with your face and voice, then stop while interest is still genuinely there.', 'Buying direct can be simpler when Amazon listings look noisy. These cards still do the early contrast job without claiming to teach a syllabus. Pair a card with your face and voice, then stop while interest is still genuinely there.', NULL, NULL, true, 'Good gift', NULL, NULL, NULL, ARRAY[]::text[], 'none'),
    ('cat_high_contrast_cards', 5, 5, 'visible', true, true, 'Best for staged card sets', 'hahaland Baby Flash Cards Visual Stimulation Cards 0-3-6-12-36 Months', 'hahaland', 'hahaland', 'https://hahaland.com/products/baby-flash-cards-baby-visual-stimulation-cards-0-3-6-12-36-months', NULL, 'GBP 12.99', 'in_stock', NULL, 'A hahaland visual card set covering early black and white pages through later colour stages, so you start simple now and keep the pack as sight grows.', 'One pack that grows with them saves another order in six months. Begin with the strongest contrast pages while focus is short. Skip any stage that looks busy until they are actually ready to linger on the page with you.', 'One pack that grows with them saves another order in six months. Begin with the strongest contrast pages while focus is short. Skip any stage that looks busy until they are actually ready to linger on the page with you.', NULL, NULL, true, 'Good gift', NULL, NULL, NULL, ARRAY[]::text[], 'none'),
    ('cat_reach_grab_toys', 1, 1, 'visible', true, false, 'Best for early finger holes', 'Oball Classic™ Easy-Grasp Toy', 'Bright Starts', 'Boots', 'https://www.boots.com/baby-einstein-oball-classic-easy-grasp-toy-10307276', NULL, 'GBP 3.99', 'in_stock', NULL, 'A lightweight Oball Classic with many soft finger holes, easy for tiny hands to grip, roll and mouth during short supervised floor play.', 'Reaching is just waking up at one to three months. Lots of holes mean a brush of fingers can become a hold without precise aim. Soft plastic survives the chew that follows, and it rolls gently when they finally tip it.', 'Reaching is just waking up at one to three months. Lots of holes mean a brush of fingers can become a hold without precise aim. Soft plastic survives the chew that follows, and it rolls gently when they finally tip it.', NULL, NULL, true, 'Good gift', NULL, NULL, NULL, ARRAY[]::text[], 'none'),
    ('cat_reach_grab_toys', 2, 2, 'visible', true, true, 'Best for bendy teether grasp', 'Winkel Rattle & Sensory Teether Toy', 'Manhattan Toy', 'Jojo Maman Bébé', 'https://www.manhattantoy.com/products/winkel', NULL, 'GBP 14.00', 'in_stock', NULL, 'A Manhattan Toy Winkel with soft bendable rings that double as a rattle and teether, easy for small hands to grab, hold and chew under watch.', 'Rigid toys miss when fists are still clumsy. Soft bendy rings give several places to catch hold, then something to gum when drool starts. Chill it briefly if gums are sore, and keep play on the mat with you nearby.', 'Rigid toys miss when fists are still clumsy. Soft bendy rings give several places to catch hold, then something to gum when drool starts. Chill it briefly if gums are sore, and keep play on the mat with you nearby.', NULL, NULL, true, 'Good gift', NULL, NULL, NULL, ARRAY[]::text[], 'none'),
    ('cat_reach_grab_toys', 3, 3, 'visible', true, true, 'Best for clipped reach play', 'Freddie the Firefly Activity Toy', 'Lamaze', 'John Lewis', 'https://www.johnlewis.com/lamaze-freddie-the-firefly-activity-toy/p109915929', NULL, 'GBP 14.99', 'in_stock', NULL, 'A Lamaze Freddie the Firefly soft toy with crinkle, squeaker, rings, a small mirror and a tethered teether, plus a clip for pram or carrier.', 'When reaching starts, variety helps more than another identical ball. Textures and a soft sound give them reasons to stretch a hand. Clip it for awake pram time, then unclip for sleep so nothing hangs in the cot overnight either.', 'When reaching starts, variety helps more than another identical ball. Textures and a soft sound give them reasons to stretch a hand. Clip it for awake pram time, then unclip for sleep so nothing hangs in the cot overnight either.', NULL, NULL, true, 'Good gift', NULL, 'Remove all packaging and tags before giving to a child', NULL, ARRAY[]::text[], 'none'),
    ('cat_reach_grab_toys', 4, 4, 'visible', true, true, 'Best for a starter kit', 'Hello Baby Newborn Kit', 'Taf Toys', 'John Lewis', 'https://www.johnlewis.com/taf-toys-hello-baby-newborn-kit/p111759988', NULL, 'GBP 32.99', 'in_stock', NULL, 'A Taf Toys Hello Baby newborn kit with flash cards, a baby safe mirror, tummy time pillow, rattle ring, crinkle cub and soft blankie for early floor play.', 'If the toy drawer is empty, a kit covers the first floor jobs in one go. Mirror and cards feed the face focus, while the soft grab pieces wait for early reaches. Use pieces one at a time so the mat does not turn into clutter.', 'If the toy drawer is empty, a kit covers the first floor jobs in one go. Mirror and cards feed the face focus, while the soft grab pieces wait for early reaches. Use pieces one at a time so the mat does not turn into clutter.', NULL, NULL, true, 'Good gift', NULL, NULL, NULL, ARRAY[]::text[], 'none'),
    ('cat_reach_grab_toys', 5, 5, 'visible', true, true, 'Best for soft fabric grasp', 'Grasping Ball - Newborn Naturals', 'Little Dutch', 'Scandiborn', 'https://www.scandiborn.co.uk/products/little-dutch-grasping-ball-newborn-naturals', NULL, 'GBP 12.71', 'in_stock', NULL, 'A Little Dutch fabric grasping ball with mixed textures and soft colours, shaped for little hands to grab, roll and explore from the earliest weeks.', 'Some parents prefer fabric over plastic for the first holds. Mixed textures invite a second grab once the first squeeze works. Keep colours gentle for now and save louder toys for when reaching is stronger and floor play lasts longer.', 'Some parents prefer fabric over plastic for the first holds. Mixed textures invite a second grab once the first squeeze works. Keep colours gentle for now and save louder toys for when reaching is stronger and floor play lasts longer.', NULL, NULL, true, 'Good gift', NULL, NULL, NULL, ARRAY[]::text[], 'none'),
    ('cat_rear_facing_car_seat', 1, 1, 'visible', true, false, 'Best for lie flat outings', 'Pebble 360 Pro2', 'Maxi-Cosi', 'John Lewis', 'https://www.johnlewis.com/maxi-cosi-pebble-360-pro2-car-seat/twillic-black/p112093409', NULL, 'GBP 207.99', 'in_stock', NULL, 'A Maxi Cosi Pebble 360 Pro2 iSize infant seat with full lie flat, 360 rotation and SlideTech access, for rear-facing travel from birth into the second year.', 'Newborns sleep hard on short drives, and upright buckets tire them fast. Lie flat keeps the first outings kinder while you stay rear-facing. Rotation and SlideTech help you lift them in without wrestling the kerb on every single school run.', 'Newborns sleep hard on short drives, and upright buckets tire them fast. Lie flat keeps the first outings kinder while you stay rear-facing. Rotation and SlideTech help you lift them in without wrestling the kerb on every single school run.', NULL, NULL, false, 'Parent buy', NULL, 'ISOFIX base sold separately; Always check car seat compatibility with your vehicle before purchase.', NULL, ARRAY[]::text[], 'none'),
    ('cat_rear_facing_car_seat', 2, 2, 'visible', true, true, 'Best for tested lie flat', 'Cloud T i-Size Rotating Baby Car Seat', 'Cybex', 'John Lewis', 'https://www.johnlewis.com/cybex-cloud-t-i-size-rotating-baby-car-seat/p110535706', NULL, 'GBP 199.95', 'in_stock', NULL, 'A Cybex Cloud T iSize rotating infant seat with lie flat recline in and out of the car, strong side impact design, and rear-facing use from birth.', 'If independent crash tests guide your shortlist, Cloud T is the seat many parents check first. Lie flat helps newborn posture on the school run for older siblings. Pair it with the matching base when you want rotation without daily belt fights.', 'If independent crash tests guide your shortlist, Cloud T is the seat many parents check first. Lie flat helps newborn posture on the school run for older siblings. Pair it with the matching base when you want rotation without daily belt fights.', NULL, NULL, false, 'Parent buy', NULL, 'ISOFIX Base T sold separately; Always check car seat compatibility with your vehicle before purchase.', NULL, ARRAY[]::text[], 'none'),
    ('cat_rear_facing_car_seat', 3, 3, 'visible', true, true, 'Best for baseless ISOFIX lifts', 'PIPA URBN R129 Baby Car Seat', 'Nuna', 'John Lewis', 'https://www.johnlewis.com/nuna-pipa-urbn-r129-baby-car-seat-caviar/p110165707', NULL, 'GBP 300.00', 'in_stock', NULL, 'A Nuna PIPA URBN infant seat at about 3.3 kilograms with integrated baseless ISOFIX, built for quick secure fits when you move between cars often.', 'Two cars or lots of taxis make a separate base feel heavy to haul. Integrated ISOFIX without a base keeps transfers simpler while staying rear-facing. Light enough to carry upstairs after a feed without pretending it is only a fashion bag.', 'Two cars or lots of taxis make a separate base feel heavy to haul. Integrated ISOFIX without a base keeps transfers simpler while staying rear-facing. Light enough to carry upstairs after a feed without pretending it is only a fashion bag.', NULL, NULL, false, 'Parent buy', NULL, 'Always check car seat compatibility with your vehicle before purchase.', NULL, ARRAY[]::text[], 'none'),
    ('cat_rear_facing_car_seat', 4, 4, 'visible', true, true, 'Best for ultra light carry', 'Pixel PRO 2.0 C Infant Carrier', 'Avionaut', 'Pramworld', 'https://www.pramworld.co.uk/avionaut-pixel-pro-2-0-c-infant-carrier-black/', NULL, 'GBP 209.00', 'in_stock', NULL, 'An Avionaut Pixel PRO 2.0 infant carrier at about 2.5 kilograms, with a modular insert for newborn positioning and rear-facing iSize travel from birth.', 'Shoulder ache is real when you lift the seat in and out all day. Extreme lightness helps if you are small or recovering from birth. Check the insert is set for a tiny baby before the first drive, especially after an early arrival.', 'Shoulder ache is real when you lift the seat in and out all day. Extreme lightness helps if you are small or recovering from birth. Check the insert is set for a tiny baby before the first drive, especially after an early arrival.', NULL, NULL, false, 'Parent buy', NULL, 'ISOFIX base sold separately; Always check car seat compatibility with your vehicle before purchase.', NULL, ARRAY[]::text[], 'none'),
    ('cat_rear_facing_car_seat', 5, 5, 'visible', true, true, 'Best for longer rear-facing', 'Turn2Me DLX i-Size R129 360° Rotating Car Seat', 'Graco', 'Amazon UK', 'https://www.amazon.co.uk/Graco-Rotating-Rearward-40-105cm-76-105cm/dp/B0D2LMQR5F', NULL, 'GBP 125.99', 'in_stock', NULL, 'A Graco Turn2Me DLX iSize seat with 360 rotation and extended rear-facing from birth to roughly four years, aimed at families wanting rotation without a premium price.', 'Infant only shells mean another seat purchase sooner. Extended rear-facing with rotation stretches the same shell further for smaller budgets. Confirm the newborn insert and recline before first use, and keep them rear-facing for as long as the limits allow.', 'Infant only shells mean another seat purchase sooner. Extended rear-facing with rotation stretches the same shell further for smaller budgets. Confirm the newborn insert and recline before first use, and keep them rear-facing for as long as the limits allow.', NULL, NULL, false, 'Parent buy', NULL, 'Side-impact protection pod needs to be fitted separately each time; Always check car seat compatibility with your vehicle before purchase.', NULL, ARRAY[]::text[], 'none'),
    ('cat_soft_carrier_sling', 1, 1, 'visible', true, false, 'Best for easy newborn carry', 'Embrace Baby Carrier', 'Ergobaby', 'Mamas & Papas', 'https://www.mamasandpapas.com/products/ergobaby-embrace-carrier-black-617825300', NULL, 'GBP 88.00', 'in_stock', NULL, 'An Ergobaby Embrace soft structured carrier ready from newborn, with a close hold and simple buckle fastening for the first year of hands free carrying.', 'Early months ask for closeness and free hands more than hiking features. Embrace skips the wrap learning curve with a few clicks and soft fabric. Good when you want them on your chest for a kettle boil without a stiff frame.', 'Early months ask for closeness and free hands more than hiking features. Embrace skips the wrap learning curve with a few clicks and soft fabric. Good when you want them on your chest for a kettle boil without a stiff frame.', NULL, NULL, false, 'Parent buy', NULL, 'Always follow recognised safe babywearing guidance and fit checks (TICKS guidelines).', NULL, ARRAY[]::text[], 'none'),
    ('cat_soft_carrier_sling', 2, 2, 'visible', true, true, 'Best for longer wear comfort', 'Baby Carrier Harmony', 'BabyBjörn', 'John Lewis', 'https://www.johnlewis.com/babybjorn-harmony-baby-carrier/p5612075', NULL, 'GBP 167.12', 'in_stock', NULL, 'A BabyBjörn Harmony soft carrier with waist belt and padded back and shoulder support, built for longer wears from newborn through the toddler years.', 'Some days you are in the carrier for hours of settling. Extra padding and a waist belt share the load when your back is already tired. Still start with short wears while you both learn the fit and check the straps.', 'Some days you are in the carrier for hours of settling. Extra padding and a waist belt share the load when your back is already tired. Still start with short wears while you both learn the fit and check the straps.', NULL, NULL, false, 'Parent buy', NULL, 'Always follow recognised safe babywearing guidance and fit checks.', NULL, ARRAY[]::text[], 'none'),
    ('cat_soft_carrier_sling', 3, 3, 'visible', true, true, 'Best for stretchy wrap hold', 'Essential Baby Wrap - Mid Grey', 'Izmi', 'Argos', 'https://www.argos.co.uk/product/9566569', NULL, 'GBP 35.00', 'in_stock', NULL, 'An Izmi stretchy cotton blend baby wrap for newborns and young infants, distributing weight across your back and shoulders with a close, snug hold.', 'Wraps give that newborn nest feeling without a structured shell. Expect a practice afternoon before tying feels quick in the hallway. Softer on the budget when you mainly need close contact for the earliest weeks at home with a new baby.', 'Wraps give that newborn nest feeling without a structured shell. Expect a practice afternoon before tying feels quick in the hallway. Softer on the budget when you mainly need close contact for the earliest weeks at home with a new baby.', NULL, NULL, false, 'Parent buy', NULL, 'Always follow recognised safe babywearing guidance and fit checks (TICKS guidelines).; Fit indoors to prevent fabric from touching the floor.', NULL, ARRAY[]::text[], 'none'),
    ('cat_soft_carrier_sling', 4, 4, 'visible', true, true, 'Best for mesh all rounder', 'Omni 360 Cool Air Mesh Baby Carrier', 'Ergobaby', 'John Lewis', 'https://www.johnlewis.com/ergobaby-omni-360-mesh-baby-carrier/p3501816', NULL, 'GBP 164.90', 'in_stock', NULL, 'An Ergobaby Omni 360 Cool Air Mesh carrier with four carry positions, ready from newborn without an insert, and breathable mesh for warmer British days.', 'If you want one carrier that lasts past the newborn bubble, Omni covers front and later hip or back carries. Mesh helps on humid afternoons. Confirm newborn positioning on day one so the hold stays high and snug on your chest.', 'If you want one carrier that lasts past the newborn bubble, Omni covers front and later hip or back carries. Mesh helps on humid afternoons. Confirm newborn positioning on day one so the hold stays high and snug on your chest.', NULL, NULL, false, 'Parent buy', NULL, 'Always follow recognised safe babywearing guidance and fit checks (TICKS guidelines).', NULL, ARRAY[]::text[], 'none'),
    ('cat_soft_carrier_sling', 5, 5, 'visible', true, true, 'Best for fine fit tweaks', 'X Baby Carrier', 'Boba', 'Boba Baby UK', 'https://bobababy.co.uk/collections/boba-x-baby-carrier', NULL, 'GBP 99.99', 'in_stock', NULL, 'A Boba X all in one soft carrier with micro adjusters for a close newborn fit that grows through toddlerhood without a separate infant insert.', 'Babies change shape fast in the first months. Fine adjusters keep the seat and straps honest as they grow, instead of living with a floppy fit. Useful if you dislike buying a newborn only carrier then another six months later.', 'Babies change shape fast in the first months. Fine adjusters keep the seat and straps honest as they grow, instead of living with a floppy fit. Useful if you dislike buying a newborn only carrier then another six months later.', NULL, NULL, false, 'Parent buy', NULL, 'Always follow recognised safe babywearing guidance and fit checks.', NULL, ARRAY[]::text[], 'none'),
    ('cat_washable_floor_play_mat', 1, 1, 'visible', true, false, 'Best for wipe-clean living rooms', 'The Mariner Playmat', 'Totter + Tumble', 'Totter + Tumble UK', 'https://totterandtumble.co.uk/products/the-mariner-playmat', NULL, 'GBP 160.00', 'in_stock', NULL, 'A Totter and Tumble Mariner playmat with high density cushioning, reversible faces and a wipe-clean surface that sits well in a lived in living room.', 'Floor play starts now with short tummy spells and supervised stretches on the ground. A cushioned wipe-clean mat protects knees and floors when milk appears. Reversible sides keep it looking intentional when guests walk through the living room after lunch at home.', 'Floor play starts now with short tummy spells and supervised stretches on the ground. A cushioned wipe-clean mat protects knees and floors when milk appears. Reversible sides keep it looking intentional when guests walk through the living room after lunch at home.', NULL, NULL, true, 'Good gift', NULL, 'Use only during awake, supervised play.', NULL, ARRAY[]::text[], 'none'),
    ('cat_washable_floor_play_mat', 2, 2, 'visible', true, true, 'Best for foldable foam value', 'Nuby Foldable Playmat Road Map', 'Nuby', 'Amazon UK', 'https://www.amazon.co.uk/Nuby-Foldable-Playmat-Road-Map/dp/B0FLPZG8JG', NULL, 'GBP 39.99', 'in_stock', NULL, 'A lightweight Nuby foldable XPE foam playmat with a road map print on one side, easy to pack away after tummy time in smaller homes.', 'Not every mat needs to look like furniture in the living room. Foldable foam covers hard floors for early movement without a big spend. Pack it behind the sofa when the room needs to be a grown-up space again after bedtime stories.', 'Not every mat needs to look like furniture in the living room. Foldable foam covers hard floors for early movement without a big spend. Pack it behind the sofa when the room needs to be a grown-up space again after bedtime stories.', NULL, NULL, true, 'Good gift', NULL, 'Use only during awake, supervised play.', NULL, ARRAY[]::text[], 'none'),
    ('cat_washable_floor_play_mat', 3, 3, 'visible', true, true, 'Best for high-contrast prints', 'Etta Loves Plant Print Reversible Playmat', 'Etta Loves', 'John Lewis', 'https://www.johnlewis.com/etta-loves-plant-print-reversible-sensory-playmat/p110367711', NULL, 'GBP 66.00', 'in_stock', NULL, 'An Etta Loves organic cotton reversible playmat with bold plant prints aimed at early looking, soft under tummy time and machine washable when spills happen.', 'Some mats are only padding. Etta Loves adds high-contrast pattern for the same short looking spells you do with cards. Soft cotton feels kinder on newborn skin, and a wash cycle sorts the inevitable dribble without much fuss at all.', 'Some mats are only padding. Etta Loves adds high-contrast pattern for the same short looking spells you do with cards. Soft cotton feels kinder on newborn skin, and a wash cycle sorts the inevitable dribble without much fuss at all.', NULL, NULL, true, 'Good gift', NULL, 'Use only during awake, supervised play.', NULL, ARRAY[]::text[], 'none'),
    ('cat_washable_floor_play_mat', 4, 4, 'visible', true, true, 'Best for thick foam tiles', 'Gus + Beau Rainbow Playmat', 'Gus + Beau', 'Gus + Beau', 'https://www.gusandbeau.com/products/rainbow-playmat-set-in-cream', NULL, 'GBP 75.00', 'in_stock', NULL, 'A Gus and Beau thick non-toxic EVA foam puzzle playmat with a simple rainbow design, giving soft cover on hard floors for early supervised play.', 'Hard tiles punish elbows during tummy time on cold floors. Thick puzzle foam softens the floor without a huge roll of mat. Interlocking tiles let you size the patch to the room and pull one piece aside for a wash if needed.', 'Hard tiles punish elbows during tummy time on cold floors. Thick puzzle foam softens the floor without a huge roll of mat. Interlocking tiles let you size the patch to the room and pull one piece aside for a wash if needed.', NULL, NULL, true, 'Good gift', NULL, 'Use only during awake, supervised play.', NULL, ARRAY[]::text[], 'none'),
    ('cat_washable_floor_play_mat', 5, 5, 'visible', true, true, 'Best for roll up floor space', 'Skip Hop Roll-up Playmat', 'Skip Hop', 'John Lewis', 'https://www.google.com/search?tbm=shop&q=Skip+Hop+Roll-up+Playmat+UK', NULL, 'GBP 81.51', 'in_stock', NULL, 'A large Skip Hop reversible wipe-clean playmat that rolls up for storage, giving a wide flat area for tummy time and early stretches on the floor.', 'Tiny mats feel cramped once both of you sit down. A larger surface that rolls up gives space to lie beside them without teetering on the edge. Wipe spills, roll it, and reclaim the floor when nap time returns again.', 'Tiny mats feel cramped once both of you sit down. A larger surface that rolls up gives space to lie beside them without teetering on the edge. Wipe spills, roll it, and reclaim the floor when nap time returns again.', NULL, NULL, true, 'Good gift', NULL, 'Use only during awake, supervised play.', NULL, ARRAY[]::text[], 'google_shopping')
  ) AS v(source_category_entity_id, pick_rank, longlist_rank, status, is_visible, is_locked, best_for_tag, product_name, brand, retailer, product_url, image_url, price_text, stock_status, age_mark_on_listing, product_description, ember_verdict, why_it_fits, caveats, buy_borrow_hold_off, gift_suitable, gift_note, ownership_note, safety_notes, evidence_tier, evidence_sources, founder_qa_flag)
)
INSERT INTO public.pl_stage3_picks (
  age_band_id,
  category_type_id,
  source_category_entity_id,
  pick_rank,
  longlist_rank,
  status,
  is_visible,
  is_locked,
  best_for_tag,
  product_name,
  brand,
  retailer,
  product_url,
  image_url,
  price_text,
  stock_status,
  age_mark_on_listing,
  product_description,
  ember_verdict,
  why_it_fits,
  caveats,
  buy_borrow_hold_off,
  gift_suitable,
  gift_note,
  ownership_note,
  safety_notes,
  evidence_tier,
  evidence_sources,
  founder_qa_flag,
  research_payload
)
SELECT
  '1-3m',
  ct.id,
  r.source_category_entity_id,
  r.pick_rank,
  r.longlist_rank,
  r.status,
  r.is_visible,
  r.is_locked,
  r.best_for_tag,
  r.product_name,
  r.brand,
  r.retailer,
  r.product_url,
  r.image_url,
  r.price_text,
  r.stock_status,
  r.age_mark_on_listing,
  r.product_description,
  r.ember_verdict,
  r.why_it_fits,
  r.caveats,
  r.buy_borrow_hold_off,
  r.gift_suitable,
  r.gift_note,
  r.ownership_note,
  r.safety_notes,
  r.evidence_tier,
  r.evidence_sources,
  r.founder_qa_flag,
  jsonb_build_object(
    'bundle_schema_version', 'stage3_ingestion_bundle_v1',
    'bundle_generated_at', '2026-07-23T19:56:01.195Z',
    'research_schema_version', 'ember_picks_research_v3',
    'source_category_entity_id', r.source_category_entity_id
  )
FROM stage3_rows r
JOIN public.pl_category_types ct
  ON ct.slug = r.source_category_entity_id
WHERE EXISTS (
  SELECT 1
  FROM public.pl_age_band_development_need_category_types abdnct
  WHERE abdnct.age_band_id = '1-3m'
    AND abdnct.category_type_id = ct.id
    AND abdnct.is_active = true
);

