  jsonb_build_object(
    'bundle_schema_version', 'stage3_ingestion_bundle_v1',
    'bundle_generated_at', '2026-07-23T19:56:01.195Z',
    'status', 'dormant_backup',
    'source_category_entity_id', r.source_category_entity_id
  )
FROM backup_rows r
JOIN public.pl_category_types ct
  ON ct.slug = r.source_category_entity_id
WHERE EXISTS (
  SELECT 1
  FROM public.pl_age_band_development_need_category_types abdnct
  WHERE abdnct.age_band_id = '1-3m'
    AND abdnct.category_type_id = ct.id
    AND abdnct.is_active = true
);

DO $$
DECLARE
  v_visible_count INTEGER;
  v_backup_count INTEGER;
BEGIN
  SELECT COUNT(*) INTO v_visible_count
  FROM public.pl_stage3_picks s
  JOIN public.pl_category_types ct ON ct.id = s.category_type_id
  WHERE s.age_band_id = '1-3m'
    AND ct.slug IN ('cat_baby_safe_mirror', 'cat_board_books', 'cat_burp_cloths_muslins', 'cat_firm_flat_mattress', 'cat_high_contrast_cards', 'cat_reach_grab_toys', 'cat_rear_facing_car_seat', 'cat_soft_carrier_sling', 'cat_washable_floor_play_mat')
    AND s.status = 'visible'
    AND s.is_visible = true;

  IF v_visible_count <> 45 THEN
    RAISE EXCEPTION 'Expected 45 visible Stage 3 picks for 1-3m, got %', v_visible_count;
  END IF;

  SELECT COUNT(*) INTO v_backup_count
  FROM public.pl_stage3_picks s
  JOIN public.pl_category_types ct ON ct.id = s.category_type_id
  WHERE s.age_band_id = '1-3m'
    AND ct.slug IN ('cat_baby_safe_mirror', 'cat_board_books', 'cat_burp_cloths_muslins', 'cat_firm_flat_mattress', 'cat_high_contrast_cards', 'cat_reach_grab_toys', 'cat_rear_facing_car_seat', 'cat_soft_carrier_sling', 'cat_washable_floor_play_mat')
    AND s.status = 'backup'
    AND s.is_visible = false;

  IF v_backup_count <> 83 THEN
    RAISE EXCEPTION 'Expected 83 backup Stage 3 picks for 1-3m, got %', v_backup_count;
  END IF;
END $$;

COMMIT;
